            entity.HasDiscriminator<string>("Discriminator");

            // Preserve EF8 id format "Product|123" (EF9 defaults to key-only)
            entity.HasRootDiscriminatorInJsonId(true);
        });
        // HasIndex removed — Cosmos DB throws at startup in EF9.
        // Manage indexing policy via Azure Portal, Bicep, or Terraform.
    }
}
